// ============ AuthService ============
// One place that knows the current user + token. EVERY other layer reads from here.
class AuthService {
  String? _token;
  User?   _user;

  String? get token => _token;
  User? get currentUser => _user;
  bool  get isLoggedIn => _token != null;

  Future<void> signIn({required String token, required User user}) async {
    _token = token; _user = user;
    _notify();
  }

  Future<void> signOut() async {
    _token = null; _user = null;
    _notify();
  }

  // Simple broadcast so listeners can react to auth changes.
  final _listeners = <VoidCallback>[];
  void addListener(VoidCallback fn) => _listeners.add(fn);
  void _notify() { for (final fn in _listeners) fn(); }
}

// ============ AnalyticsService ============
// Fire-and-forget event logging. Never blocks the UI.
class AnalyticsService {
  AnalyticsService(this._sender);
  final AnalyticsSender _sender;   // wraps Firebase/Mixpanel/Segment

  void log(String event, {Map<String, Object?> props = const {}}) {
    unawaited(_sender.send(event, props));   // never awaited
  }

  void screen(String name) => log('screen_view', props: {'name': name});
}

// ============ ConnectivityService ============
// Watches network state so features can react (show offline banner, defer sync).
class ConnectivityService {
  final _controller = StreamController<bool>.broadcast();
  Stream<bool> get onChanged => _controller.stream;

  Future<void> init() async {
    Connectivity().onConnectivityChanged.listen((result) {
      _controller.add(result != ConnectivityResult.none);
    });
  }

  Future<bool> get isOnline async =>
      (await Connectivity().checkConnectivity()) != ConnectivityResult.none;
}

// ============ Wiring at the composition root ============
void setupServices() {
  getIt.registerSingleton<AuthService>(AuthService());
  getIt.registerSingleton<AnalyticsService>(AnalyticsService(FirebaseAnalyticsSender()));
  getIt.registerSingleton<ConnectivityService>(ConnectivityService()..init());
}

// ============ Consumed by a Repository ============
class OrderRepositoryImpl implements OrderRepository {
  OrderRepositoryImpl(this._api, this._auth, this._analytics);
  final Dio _api;
  final AuthService _auth;
  final AnalyticsService _analytics;

  @override
  Future<Order> placeOrder(Cart cart) async {
    final resp = await _api.post('/orders',
      data: cart.toJson(),
      options: Options(headers: {'Authorization': 'Bearer ${_auth.token}'}),
    );
    _analytics.log('order_placed', props: {'total': cart.total});
    return Order.fromJson(resp.data);
  }
}

// Notice: Repository uses BOTH Services. Services don't know about Repositories.
// This is the correct dependency direction — Services are 'below' Repositories.
